function [qvalues,k,passed]=performFDR(pvalues,pThreshold)% Performs FDR correction per #CITATION HEREif(istable(pvalues))    pvalues=table2array(pvalues);endif(nargin<2)    pThreshold=0.05;endqvalues=nan(size(pvalues));kVals=nan(size(pvalues(:)));[pSorted,pIdx]=sort(pvalues(:));       numP=length(pSorted);kPass=zeros(1,numP);m=numP;for i=1:numP        qThreshold=pThreshold/m*i;    k=numP-i+1;    qvalues(pIdx(i))=pvalues(pIdx(i))*m/i;        if(qvalues(pIdx(i))<=pThreshold&&pvalues(pIdx(i))<=0.05)        kPass(pIdx(i))=1;    end    kVals(pIdx(i))=i;endk_ind=find(kPass==1);if(isempty(k_ind))    k=1;else   k=1; endqvalues=pvalues*m/k;qvalues(qvalues>1)=1;passed=qvalues<=pThreshold;if(any(kPass(:)))   k=max(kVals(kPass(:)==1));   qvalues=pvalues*m/k;   passed=qvalues<=pThreshold&pvalues<0.05;end